// Load the AWS SDK and SQS library
    const {
        ClientFactory,
    } = require('aws-sdk');

    let sqs;
    
    function getSQS() {
        if (sqs)
            return Promise.resolve(sqs);

        const config = new ClientFactory({region: "us-east-1"});
        
        // Construct the SQS object with client factory.
        const sqsclientfactory = ClientFactory();
    
        sqs = new sqsclientfactory.SQSClient({
          apiVersion:"2013-11-05", 
          region:'us-east-1',
          endpoint: 'http://sqs.us-east-1.amazonaws.com'
        });

        return Promise.resolve(sqs);
    }

// Helper functions to get messages from SQS queue and delete them.
    function getQueueMessages(){
        const sqs = getSQS();
        
        var params = {
            QueueUrl: "https://sqs.us-east-1.amazonaws.com/349707835690/lambda-function", //The URL of our SQS queue. You need to change this URL based on your own SQS queue
        };
        
        return new Promise((resolve,reject)=>{
            sqs.receiveMessage(params,(err,data)=>{
                if (err)
                    reject(err);
        
                const messages = data.Messages;
                
                for (let message of messages){
                    
                    var deleteParams = {
                        QueueUrl:"https://sqs.us-east-1.amazonaws.com/349707835690/lambda-function", //The URL of our SQS queue. You need to change this URL based on your own SQS queue
                        ReceiptHandle: message.ReceiptHandle
                    };
                    
                    sqs.deleteMessage(deleteParams,(err,data)=>{
                       if (err)
                            reject(err);
    
                       resolve(message);
                    });
                }
            })
        }).catch((e)=>{console.log(e)});
    }

// Helper functions to send messages back to SQS queue after processing the message    
    function sendToSQSQueue(message,status){
        const sqs = getSQS();

        var params = {
            QueueUrl:"https://sqs.us-east-1.amazonaws.com/349707835690/lambda-function", //The URL of our SQS queue. You need to change this URL based on your own SQS queue
            MessageBody:message
        };

        sqs.sendMessage(params,(err,data)=>{
            
            const sendParams = {
                QueueUrl:"https://sqs.us-east-1.amazonaws.com/349707835690/lambda-function", //The URL of our SQS queue. You need to change this URL based on your own SQS queue
                ReceiptHandle:message
            };

            if (status==="Failed"){
                sqs.changeMessageVisibility(sendParams,(err,data)=>{
                    console.log("Error in processing, message put back in Queue again");

                    err ? console.error(err) : 
                    console.log(`Successfully removed visibilityTimeout: ${err}`);
                })
            }
        });
    }

// Function to convert SQS messages to JSON object
    function getSqsMessageJSON(message){
        
        let message_ = Buffer.from(message,"base64").toString();
    
        const parsedData = JSON.parse(message_);

        return parsedData;
    }

// Helper function to parse a SQS message
    async function parseSqsMessage(sqs){
        try {
            let message = await getQueueMessages();
            
            let data = getSqsMessageJSON(message.Body);
            
            console.log(`Successfully processed message: ${data}`);

            const order_id = data["order"]; // The order ID that is contained in our SQS messages.
        
            return {
                body: data,
                orderId: order_id
            }
        } catch (e){console.log(e);}
    }

