// Helper function to update payment status in DynamoDB (in our case S3 bucket) with the response from callExternalAPI()
    async function updateStatus(status,paymentData){
        const Bucket = new s3({region:'us-east-1'}); // Replace us-east-1 based on your region.

        var params = {
            Bucket: 'bucket', // The name of our S3 bucket that contains payment status.
            Key:"order-id", // This is a dummy key for now since it can be replaced later if required to. 
            Body:`{status: ${status}, orderId: ${paymentData["orderId"]}, firstName:${paymentData["firstName"]}}` 
        };
        
        return new Promise((resolve,reject)=>{
            Bucket.putObject(params,(err,data)=>{
                err ? reject(err) : resolve("Success");
            })
        });
    }

